import{_ as t,o,c as l,ag as i}from"./chunks/framework.CAXxHpAX.js";const d=JSON.parse('{"title":"术语表","description":"","frontmatter":{},"headers":[],"relativePath":"glossary.md","filePath":"glossary.md"}'),n={name:"glossary.md"};function a(s,r,e,g,h,c){return o(),l("div",null,[...r[0]||(r[0]=[i('<h1 id="术语表" tabindex="-1">术语表 <a class="header-anchor" href="#术语表" aria-label="Permalink to &quot;术语表&quot;">​</a></h1><h2 id="postgresql-基础" tabindex="-1">PostgreSQL 基础 <a class="header-anchor" href="#postgresql-基础" aria-label="Permalink to &quot;PostgreSQL 基础&quot;">​</a></h2><ul><li><strong>Database</strong>：一个相对独立的数据世界。</li><li><strong>Schema</strong>：数据库内部的命名空间。</li><li><strong>Table</strong>：业务对象、事件或关系的数据化表达。</li><li><strong>Row</strong>：一条事实记录。</li><li><strong>Column</strong>：事实的属性。</li><li><strong>Primary Key</strong>：解决记录身份问题。</li><li><strong>Foreign Key</strong>：解决表之间关系问题。</li><li><strong>Transaction</strong>：让多步修改表现得像一个可靠动作。</li><li><strong>Index</strong>：用写入成本换读取路径，加速特定查询访问。</li><li><strong>Partition</strong>：为持续增长的大表建立可管理、可裁剪的物理边界。</li><li><strong>Materialized View</strong>：把重复查询结果提前算好并存下来，需要刷新。</li><li><strong>WAL</strong>：Write-Ahead Log，PostgreSQL 的预写日志，是逻辑复制和 CDC 的基础。</li></ul><h2 id="数据建模" tabindex="-1">数据建模 <a class="header-anchor" href="#数据建模" aria-label="Permalink to &quot;数据建模&quot;">​</a></h2><ul><li><strong>Fact Table</strong>：记录业务事实的表，一行代表一笔交易、一次事件或一个度量。</li><li><strong>Dimension Table</strong>：描述业务对象属性的表，如用户、商品、地区。</li><li><strong>Star Schema</strong>：以事实表为中心、维度表围绕的星型建模方式。</li><li><strong>ODS / DWD / DWS / ADS</strong>：数仓分层，从原始数据到明细、汇总和应用层。</li><li><strong>Metric</strong>：可量化的业务度量，如 GMV、DAU、转化率。</li><li><strong>Granularity</strong>：表中一行代表的业务粒度。</li></ul><h2 id="数据平台" tabindex="-1">数据平台 <a class="header-anchor" href="#数据平台" aria-label="Permalink to &quot;数据平台&quot;">​</a></h2><ul><li><strong>OLTP</strong>：面向业务交易，高频小事务、低延迟和强一致优先。</li><li><strong>OLAP</strong>：面向数据分析，大范围扫描、聚合和吞吐优先。</li><li><strong>ETL / ELT</strong>：数据抽取、转换、装载的链路模式。</li><li><strong>CDC</strong>：捕获数据库变更并形成持续数据流。</li><li><strong>Data Lineage</strong>：数据从源到目标的流转路径和依赖关系。</li></ul><h2 id="批处理与流处理" tabindex="-1">批处理与流处理 <a class="header-anchor" href="#批处理与流处理" aria-label="Permalink to &quot;批处理与流处理&quot;">​</a></h2><ul><li><strong>Spark</strong>：大规模分布式批处理和数据转换引擎。</li><li><strong>Flink</strong>：有状态流计算引擎，支持事件时间、窗口和 Exactly Once 语义。</li><li><strong>Kafka</strong>：分布式事件流平台，用 Topic 和 Partition 承接持续数据流。</li><li><strong>Watermark</strong>：Flink 中判断事件时间推进到哪里的机制，决定窗口何时输出。</li><li><strong>Exactly Once</strong>：端到端处理语义，需要 Source、Checkpoint 和 Sink 共同配合。</li></ul><h2 id="olap-引擎" tabindex="-1">OLAP 引擎 <a class="header-anchor" href="#olap-引擎" aria-label="Permalink to &quot;OLAP 引擎&quot;">​</a></h2><ul><li><strong>ClickHouse</strong>：列式高性能 OLAP 数据库，核心引擎为 MergeTree。</li><li><strong>MergeTree</strong>：ClickHouse 的核心表引擎，通过排序键和稀疏索引优化分析查询。</li><li><strong>Doris</strong>：面向实时数仓和 BI 的 MPP 分析数据库。</li><li><strong>DuckDB</strong>：本地嵌入式 OLAP 数据库，可直接查询 Parquet 文件。</li></ul><h2 id="湖仓" tabindex="-1">湖仓 <a class="header-anchor" href="#湖仓" aria-label="Permalink to &quot;湖仓&quot;">​</a></h2><ul><li><strong>Lakehouse</strong>：用表格式把对象存储中的文件组织成可管理的分析表。</li><li><strong>Iceberg</strong>：湖仓表格式，支持快照、schema 演化、分区演化和时间旅行。</li><li><strong>Delta Lake</strong>：湖仓表格式，提供 ACID 事务和版本管理。</li><li><strong>Hudi</strong>：湖仓表格式，支持增量处理和近实时数据入湖。</li><li><strong>Parquet</strong>：列式存储格式，适合分析查询和跨引擎共享。</li><li><strong>Catalog</strong>：管理湖仓表元数据、快照和 schema 的目录服务。</li><li><strong>Snapshot</strong>：湖仓表在某一时刻的完整数据版本。</li></ul><h2 id="向量数据库" tabindex="-1">向量数据库 <a class="header-anchor" href="#向量数据库" aria-label="Permalink to &quot;向量数据库&quot;">​</a></h2><ul><li><strong>Embedding</strong>：把文本、图片、代码等对象转换成向量。</li><li><strong>Vector Search</strong>：基于向量相似度检索内容。</li><li><strong>HNSW</strong>：分层可导航小世界图索引，适合高召回低延迟场景。</li><li><strong>IVF</strong>：倒排文件索引，通过聚类加速大规模向量检索。</li><li><strong>Chunk</strong>：文档切分后的语义片段，是 RAG 检索的基本单位。</li><li><strong>Rerank</strong>：对召回结果重新排序，提升最终答案质量。</li><li><strong>pgvector</strong>：PostgreSQL 的向量扩展，适合中小规模 RAG 场景。</li><li><strong>Milvus</strong>：专门向量数据库，适合大规模向量检索。</li></ul><h2 id="图数据库" tabindex="-1">图数据库 <a class="header-anchor" href="#图数据库" aria-label="Permalink to &quot;图数据库&quot;">​</a></h2><ul><li><strong>Node / Vertex</strong>：图中的实体节点。</li><li><strong>Edge / Relationship</strong>：实体之间的关系。</li><li><strong>Property Graph</strong>：节点和边都可以带属性的图模型。</li><li><strong>Cypher</strong>：Neo4j 的图查询语言，用模式匹配表达路径查询。</li><li><strong>GraphRAG</strong>：结合图关系和检索增强生成的 AI 应用模式。</li><li><strong>Neo4j</strong>：生态成熟的图数据库，适合知识图谱和路径查询。</li></ul><h2 id="数据治理" tabindex="-1">数据治理 <a class="header-anchor" href="#数据治理" aria-label="Permalink to &quot;数据治理&quot;">​</a></h2><ul><li><strong>Data Governance</strong>：质量、元数据、血缘、权限、指标和知识治理的综合体系。</li><li><strong>Metadata</strong>：描述数据的数据，包括技术元数据和业务元数据。</li><li><strong>Data Quality</strong>：数据的完整性、准确性、一致性、唯一性和及时性。</li><li><strong>Metric Governance</strong>：统一指标定义、口径、血缘和版本管理。</li></ul>',19)])])}const P=t(n,[["render",a]]);export{d as __pageData,P as default};
